// shadcn
import { Button } from "@/components/ui/button";

// assets
import { CheckIcon, XIcon } from "lucide-react";

type Feature = { label: string; included: boolean };

// constants
const plans: {
  id: number;
  name: string;
  price: number;
  features: Feature[];
}[] = [
  {
    id: 1,
    name: "Free",
    price: 24,
    features: [
      { label: "20 Gb", included: true },
      { label: "25 Users", included: false },
      { label: "50 CP", included: false },
      { label: "1 Active Session", included: false }
    ]
  },
  {
    id: 2,
    name: "Basic",
    price: 49,
    features: [
      { label: "20 Gb", included: true },
      { label: "25 Users", included: true },
      { label: "50 CP", included: false },
      { label: "1 Active Session", included: false }
    ]
  },
  {
    id: 3,
    name: "Advanced",
    price: 74,
    features: [
      { label: "20 Gb", included: true },
      { label: "25 Users", included: true },
      { label: "50 CP", included: true },
      { label: "1 Active Session", included: false }
    ]
  },
  {
    id: 4,
    name: "Professional",
    price: 99,
    features: [
      { label: "20 Gb", included: true },
      { label: "25 Users", included: true },
      { label: "50 CP", included: true },
      { label: "1 Active Session", included: true }
    ]
  }
];

//  ------------------------------ | PRICING 5 | ------------------------------  //

export default function Pricing5() {
  return (
    <section className="py-20">
      <div className="mx-auto container px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-12">
          <h2 className="text-foreground">Pricing Plans</h2>
        </div>

        {/* 4-column split with dividers */}
        <div className="grid grid-cols-1 sm:grid-cols-4 divide-y sm:divide-y-0 sm:divide-x divide-border">
          {plans.map((plan) => (
            <div
              key={plan.id}
              className="flex flex-col items-center text-center gap-5 px-6 py-4"
            >
              {/* Plan name */}
              <h4 className="text-foreground font-bold">{plan.name}</h4>

              {/* Price */}
              <div className="flex flex-col items-center">
                <span className="text-5xl font-bold text-primary">
                  ${plan.price}
                </span>
                <span className="text-muted-foreground font-bold text-md">
                  /per month
                </span>
              </div>

              {/* Features */}
              <ul className="flex flex-col gap-2 w-full">
                {plan.features.map((feature) => (
                  <li
                    key={feature.label}
                    className="flex items-center justify-center gap-2"
                  >
                    {feature.included ? (
                      <CheckIcon className="size-5 text-primary shrink-0" />
                    ) : (
                      <XIcon className="size-5 text-primary/40 shrink-0" />
                    )}
                    <span
                      className={`text-md ${feature.included ? "text-foreground" : "text-muted-foreground line-through"}`}
                    >
                      {feature.label}
                    </span>
                  </li>
                ))}
              </ul>

              {/* CTA — link style */}
              <Button
                variant="link"
                className="text-primary p-0 h-auto hover:text-yellow-500"
              >
                Get Started
              </Button>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
